import{_ as l,c as o,o as i,a3 as a}from"./chunks/framework.CTM16EAR.js";const h=JSON.parse('{"title":"Pomotention 分层约定（工作版）","description":"","frontmatter":{"search":false},"headers":[],"relativePath":"dev-log/architecture-layering.md","filePath":"dev-log/architecture-layering.md","lastUpdated":1778552005000}'),c={name:"dev-log/architecture-layering.md"};function d(t,e,s,n,r,u){return i(),o("div",null,e[0]||(e[0]=[a('<h1 id="pomotention-分层约定-工作版" tabindex="-1">Pomotention 分层约定（工作版） <a class="header-anchor" href="#pomotention-分层约定-工作版" aria-label="Permalink to &quot;Pomotention 分层约定（工作版）&quot;">​</a></h1><h2 id="目标" tabindex="-1">目标 <a class="header-anchor" href="#目标" aria-label="Permalink to &quot;目标&quot;">​</a></h2><ul><li>降低单文件体积，避免 <code>view</code> 持续膨胀。</li><li>统一 <code>view / component / composable / service / action</code> 的职责边界。</li><li>给键盘、点击、后续 AI/CLI 提供同一命令入口。</li></ul><h2 id="分层定义" tabindex="-1">分层定义 <a class="header-anchor" href="#分层定义" aria-label="Permalink to &quot;分层定义&quot;">​</a></h2><ul><li><code>views/</code><ul><li>路由页面编排层，只做组装与接线。</li><li>不承载复杂业务流程与长逻辑函数。</li></ul></li><li><code>components/</code><ul><li>可渲染 UI 单元，负责局部交互与输入体验。</li><li>通过 <code>emit</code> 上抛意图，不直接耦合全局命令。</li></ul></li><li><code>composables/</code><ul><li>可复用的有状态行为模块，组织跨组件流程。</li><li>推荐按域分组，例如 <code>composables/home/*</code>。</li></ul></li><li><code>services/</code><ul><li>纯业务函数和数据处理逻辑，尽量无 Vue 依赖。</li><li>便于独立测试和复用。</li></ul></li><li><code>actions/</code><ul><li>统一命令层（Action Layer），管理 <code>canRun/run</code>。</li><li>键盘、点击、AI/CLI 都应汇聚到此层。</li></ul></li></ul><h2 id="约束规则" tabindex="-1">约束规则 <a class="header-anchor" href="#约束规则" aria-label="Permalink to &quot;约束规则&quot;">​</a></h2><ul><li>超过约 800 行的 <code>view</code> 或 <code>component</code>，优先拆分。</li><li>新增中复杂逻辑默认进入 <code>composable</code> 或 <code>service</code>，不要直接塞进 <code>view</code>。</li><li><code>MainLayout</code> 负责全局输入路由，不承担业务细节。</li><li>命令触发路径优先走 <code>actions</code>，避免旁路调用。</li></ul><h2 id="当前执行策略" tabindex="-1">当前执行策略 <a class="header-anchor" href="#当前执行策略" aria-label="Permalink to &quot;当前执行策略&quot;">​</a></h2><ul><li>先将 <code>HomeView</code> 的 planner 键盘与行编辑逻辑迁移到 <code>composables/home/</code>。</li><li>保留旧路径兼容导出，逐步迁移引用。</li><li>每次功能迭代同步执行“拆分 + 接线”而非继续堆积。</li></ul><h2 id="composables-目录分组-阶段一" tabindex="-1">Composables 目录分组（阶段一） <a class="header-anchor" href="#composables-目录分组-阶段一" aria-label="Permalink to &quot;Composables 目录分组（阶段一）&quot;">​</a></h2><ul><li><code>composables/keyboard/*</code><ul><li>全局快捷键与各区域命令注册。</li></ul></li><li><code>composables/home/*</code><ul><li>Home 页面域内复用行为（如 planner 键盘、行编辑）。</li><li>提供 <code>home/index.ts</code> 作为统一导出入口。</li></ul></li><li><code>composables/platform/index.ts</code><ul><li>设备、PWA、跨平台触控与外部文档入口能力导出。</li></ul></li><li><code>composables/layout/index.ts</code><ul><li>视口、窗口、拖拽、尺寸相关能力导出。</li></ul></li><li><code>composables/search/index.ts</code><ul><li>搜索页相关能力导出。</li></ul></li><li><code>composables/chart/index.ts</code><ul><li>图表相关能力导出。</li></ul></li><li><code>composables/planner/index.ts</code><ul><li>计划视图数据与统计能力导出。</li></ul></li><li><code>composables/activity/index.ts</code><ul><li>活动域交互能力导出。</li></ul></li><li><code>composables/task/index.ts</code><ul><li>任务域交互与光标反馈能力导出。</li></ul></li><li><code>composables/sync/index.ts</code><ul><li>同步、相对时间与迁移能力导出。</li></ul></li><li><code>composables/ai/index.ts</code><ul><li>AI 对话能力导出。</li></ul></li></ul>',11)]))}const p=l(c,[["render",d]]);export{h as __pageData,p as default};
